INSERT INTO public.play_questions (domain, category, difficulty_rating, content, options, correct_answer_index, explanation)
VALUES
  ('academic', 'physics', 1380, $p001c${"text":"Why does a particle dropped from a satellite orbiting the Earth not fall straight down to the Earth's surface?","pack":"puc_physics_jee_neet_100","qtype":"conceptual","block":"kinematics"}$p001c$::jsonb, $p001o$["It keeps the satellite’s tangential orbital speed (inertia) and continues in orbit alongside the satellite.","Gravity stops acting on it the instant it is released.","It has zero horizontal velocity, so it falls straight toward Earth’s centre.","The satellite’s cabin air pushes it back into the satellite."]$p001o$::jsonb, 0, $p001e$The particle retains tangential orbital velocity; it shares the satellite’s orbit rather than falling radially.$p001e$),
  ('academic', 'physics', 1386, $p002c${"text":"A block of mass \\(m\\) rests on a smooth wedge of mass \\(M\\) with inclination \\(\\theta\\). What horizontal force \\(F\\) on the wedge keeps the block stationary relative to the wedge?","pack":"puc_physics_jee_neet_100","qtype":"numerical","block":"kinematics"}$p002c$::jsonb, $p002o$["\\(F = (M+m)g\\tan\\theta\\)","\\(F = Mg\\sin\\theta\\)","\\(F = (M+m)g\\sin\\theta\\)","\\(F = mg\\cos\\theta\\)"]$p002o$::jsonb, 0, $p002e$Pseudo-force \(ma\) along the incline balances \(mg\sin\theta\) with \(a = g\tan\theta\); total mass \((M+m)\).$p002e$),
  ('academic', 'physics', 1392, $p003c${"text":"In a conical pendulum, is the string tension greater than, equal to, or strictly less than the weight of the bob?","pack":"puc_physics_jee_neet_100","qtype":"conceptual","block":"kinematics"}$p003c$::jsonb, $p003o$["Strictly greater than \\(mg\\).","Equal to \\(mg\\).","Strictly less than \\(mg\\).","Zero when the bob moves fastest."]$p003o$::jsonb, 0, $p003e$\(T\cos\theta = mg\) gives \(T = mg/\cos\theta > mg\) for \(\theta > 0\).$p003e$),
  ('academic', 'physics', 1398, $p004c${"text":"A block takes \\(n\\) times longer to slide down a rough incline (angle \\(\\theta\\), kinetic friction \\(\\mu\\)) than down a smooth incline of the same angle and length. Find \\(\\mu\\).","pack":"puc_physics_jee_neet_100","qtype":"numerical","block":"kinematics"}$p004c$::jsonb, $p004o$["\\(\\mu = \\tan\\theta\\,(1 - 1/n^2)\\)","\\(\\mu = \\tan\\theta\\,(1 - 1/n)\\)","\\(\\mu = \\cot\\theta\\,(1 - 1/n^2)\\)","\\(\\mu = \\tan\\theta / n^2\\)"]$p004o$::jsonb, 0, $p004e$\(t \propto 1/\sqrt{a}\); \(a_{\text{smooth}} = g\sin\theta\), \(a_{\text{rough}} = g(\sin\theta - \mu\cos\theta)\); ratio yields the result.$p004e$),
  ('academic', 'physics', 1404, $p005c${"text":"Can a body be in translational equilibrium while not in rotational equilibrium?","pack":"puc_physics_jee_neet_100","qtype":"conceptual","block":"kinematics"}$p005c$::jsonb, $p005o$["Yes — net force can be zero while net torque is non-zero (e.g. a couple).","No — equilibrium always requires both translational and rotational balance.","Only if the body is a single point mass.","Only in non-inertial frames."]$p005o$::jsonb, 0, $p005e$Two equal and opposite parallel forces give zero net force but non-zero torque.$p005e$),
  ('academic', 'physics', 1411, $p006c${"text":"A variable force \\(F = kx^2\\) acts on a particle. Total work from \\(x=0\\) to \\(x=A\\)?","pack":"puc_physics_jee_neet_100","qtype":"numerical","block":"kinematics"}$p006c$::jsonb, $p006o$["\\(kA^3/3\\)","\\(kA^2/2\\)","\\(kA^3\\)","\\(kA/3\\)"]$p006o$::jsonb, 0, $p006e$\(W = \int_0^A kx^2\,dx = kA^3/3\).$p006e$),
  ('academic', 'physics', 1417, $p007c${"text":"Does the coefficient of static friction depend on the macroscopic contact area between two rigid bodies (standard model)?","pack":"puc_physics_jee_neet_100","qtype":"conceptual","block":"kinematics"}$p007c$::jsonb, $p007o$["No — it depends on materials and normal force, not apparent area.","Yes — larger area always increases \\(\\mu_s\\).","Yes — it is inversely proportional to contact area.","Only for rolling, not sliding."]$p007o$::jsonb, 0, $p007e$Amontons’ model: \(\mu_s\) is material/normal-force dependent, not nominal area.$p007e$),
  ('academic', 'physics', 1423, $p008c${"text":"Rain falls vertically at \\(4\\ \\mathrm{m/s}\\). A man runs horizontally at \\(3\\ \\mathrm{m/s}\\). At what angle from the vertical should he tilt the umbrella to block drops (relative to him)?","pack":"puc_physics_jee_neet_100","qtype":"numerical","block":"kinematics"}$p008c$::jsonb, $p008o$["\\(\\tan^{-1}(3/4)\\) (about \\(36.9^\\circ\\))","\\(\\tan^{-1}(4/3)\\)","\\(\\sin^{-1}(3/5)\\) from the horizontal only","\\(45^\\circ\\) always"]$p008o$::jsonb, 0, $p008e$Relative velocity of rain w.r.t. man has horizontal \(3\) and downward \(4\); \(\tan\phi = 3/4\) from vertical.$p008e$),
  ('academic', 'physics', 1429, $p009c${"text":"For a projectile launched at angle \\(\\theta\\), where along the trajectory is its speed an absolute minimum?","pack":"puc_physics_jee_neet_100","qtype":"conceptual","block":"kinematics"}$p009c$::jsonb, $p009o$["At the highest point (apex).","At the launch point.","At impact with the ground.","Midway horizontally only."]$p009o$::jsonb, 0, $p009e$Vertical component is zero at apex; horizontal \(v\cos\theta\) remains — minimum speed.$p009e$),
  ('academic', 'physics', 1435, $p010c${"text":"Two masses \\(m_1 > m_2\\) on a massless string over a smooth pulley (Atwood machine). Downward acceleration of the centre of mass?","pack":"puc_physics_jee_neet_100","qtype":"numerical","block":"kinematics"}$p010c$::jsonb, $p010o$["\\(\\bigl(\\frac{m_1-m_2}{m_1+m_2}\\bigr)^2 g\\)","\\(\\frac{m_1-m_2}{m_1+m_2}\\,g\\)","\\(\\frac{m_1+m_2}{m_1-m_2}\\,g\\)","\\(g/2\\) always"]$p010o$::jsonb, 0, $p010e$Each mass accelerates at \(a = g(m_1-m_2)/(m_1+m_2)\); \(a_{\mathrm{cm}} = (m_1 a - m_2 a)/(m_1+m_2)\).$p010e$),
  ('academic', 'physics', 1442, $p011c${"text":"If the net kinetic energy of a multi-particle system is exactly zero, is the total momentum necessarily zero?","pack":"puc_physics_jee_neet_100","qtype":"conceptual","block":"work_energy"}$p011c$::jsonb, $p011o$["Yes — every particle has zero speed, so total momentum is zero.","No — momentum can be non-zero while \\(K=0\\).","Only for two particles.","Only in the centre-of-mass frame."]$p011o$::jsonb, 0, $p011e$\(K\) is a sum of non-negative terms; \(K=0\) implies each \(v_i=0\).$p011e$),
  ('academic', 'physics', 1448, $p012c${"text":"A particle on a rigid string of length \\(L\\): minimum horizontal speed at the lowest point to complete a vertical circle without the string going slack?","pack":"puc_physics_jee_neet_100","qtype":"numerical","block":"work_energy"}$p012c$::jsonb, $p012o$["\\(\\sqrt{5gL}\\)","\\(\\sqrt{gL}\\)","\\(\\sqrt{2gL}\\)","\\(\\sqrt{3gL}\\)"]$p012o$::jsonb, 0, $p012e$Top requires \(v_{\mathrm{top}} \ge \sqrt{gL}\); energy from bottom gives \(\sqrt{5gL}\).$p012e$),
  ('academic', 'physics', 1454, $p013c${"text":"Does kinetic friction always decrease the kinetic energy of the body it acts on?","pack":"puc_physics_jee_neet_100","qtype":"conceptual","block":"work_energy"}$p013c$::jsonb, $p013o$["No — friction opposes relative motion; on an accelerating belt it can increase the block’s kinetic energy.","Yes — friction always removes mechanical energy.","Yes — unless the surface is frictionless.","Only for static friction, never kinetic."]$p013o$::jsonb, 0, $p013e$Example: friction forward on a block on an accelerating truck increases its \(K\).$p013e$),
  ('academic', 'physics', 1460, $p014c${"text":"A car of mass \\(m\\) starts from rest with engine delivering constant power \\(P\\). Velocity as a function of time \\(t\\)?","pack":"puc_physics_jee_neet_100","qtype":"numerical","block":"work_energy"}$p014c$::jsonb, $p014o$["\\(v = \\sqrt{2Pt/m}\\)","\\(v = Pt/m\\)","\\(v = \\sqrt{Pt/(2m)}\\)","\\(v = P^2 t^2/m\\)"]$p014o$::jsonb, 0, $p014e$\(W = Pt = \tfrac12 mv^2\) from rest.$p014e$),
  ('academic', 'physics', 1466, $p015c${"text":"In uniform circular motion, work done by the centripetal force over half a revolution?","pack":"puc_physics_jee_neet_100","qtype":"conceptual","block":"work_energy"}$p015c$::jsonb, $p015o$["Zero.","\\(\\pi r F\\).","\\(2\\pi r F\\).","\\(Fr\\)."]$p015o$::jsonb, 0, $p015e$Centripetal force is perpendicular to each displacement element; \(W=0\).$p015e$),
  ('academic', 'physics', 1473, $p016c${"text":"A spring constant \\(k\\) is cut into three equal pieces. Spring constant of one piece?","pack":"puc_physics_jee_neet_100","qtype":"numerical","block":"work_energy"}$p016c$::jsonb, $p016o$["\\(3k\\)","\\(k/3\\)","\\(k\\)","\\(9k\\)"]$p016o$::jsonb, 0, $p016e$\(k \propto 1/L\); length \(\to L/3\) gives stiffness \(\times 3\).$p016e$),
  ('academic', 'physics', 1479, $p017c${"text":"Why are mountain roads banked inward on sharp curves?","pack":"puc_physics_jee_neet_100","qtype":"conceptual","block":"work_energy"}$p017c$::jsonb, $p017o$["The normal force’s horizontal component helps provide centripetal acceleration, reducing reliance on friction alone.","Banking increases weight along the slope only.","To increase rolling friction deliberately.","To make vehicles accelerate uphill."]$p017o$::jsonb, 0, $p017e$Banked turn: \(N\sin\theta\) contributes to \(mv^2/r\).$p017e$),
  ('academic', 'physics', 1485, $p018c${"text":"A ball dropped from height \\(h\\); coefficient of restitution \\(e\\). Total vertical distance travelled before rest?","pack":"puc_physics_jee_neet_100","qtype":"numerical","block":"work_energy"}$p018c$::jsonb, $p018o$["\\(h\\,(1+e^2)/(1-e^2)\\)","\\(h/(1-e)\\)","\\(h(1+e)/(1-e)\\)","\\(2h/(1-e^2)\\)"]$p018o$::jsonb, 0, $p018e$Sum of bounce heights forms a geometric series.$p018e$),
  ('academic', 'physics', 1491, $p019c${"text":"Can gravitational or electrostatic potential energy of a bound system be negative?","pack":"puc_physics_jee_neet_100","qtype":"conceptual","block":"work_energy"}$p019c$::jsonb, $p019o$["Yes — potential energy is defined up to a constant; attractive forces often use negative values.","No — energy cannot be negative.","Only for unbound systems.","Only at absolute zero."]$p019o$::jsonb, 0, $p019e$Negative \(U\) means energy must be supplied to separate the parts to infinity.$p019e$),
  ('academic', 'physics', 1497, $p020c${"text":"Particle in a circle of radius \\(R\\) with constant tangential acceleration \\(a_t = k\\). Time when \\(|a_c| = |a_t|\\) (\\(a_c\\) centripetal)?","pack":"puc_physics_jee_neet_100","qtype":"numerical","block":"work_energy"}$p020c$::jsonb, $p020o$["\\(t = \\sqrt{R/k}\\)","\\(t = R/k\\)","\\(t = \\sqrt{k/R}\\)","\\(t = kR\\)"]$p020o$::jsonb, 0, $p020e$\(v = kt\), \(a_c = v^2/R = k^2 t^2/R\); set equal to \(k\).$p020e$),
  ('academic', 'physics', 1504, $p021c${"text":"Two solid spheres, same mass, same \\(\\omega\\): one aluminum, one lead. Which has higher rotational kinetic energy?","pack":"puc_physics_jee_neet_100","qtype":"conceptual","block":"rotation"}$p021c$::jsonb, $p021o$["Aluminum — lower density ⇒ larger radius for same \\(m\\) ⇒ larger \\(I\\) ⇒ larger \\(K_{\\mathrm{rot}}\\).","Lead — denser means higher \\(K_{\\mathrm{rot}}\\).","They are always equal if \\(m,\\omega\\) match.","Depends only on colour of paint."]$p021o$::jsonb, 0, $p021e$\(I = \frac{2}{5}mR^2\); larger \(R\) for Al at fixed \(m\).$p021e$),
  ('academic', 'physics', 1510, $p022c${"text":"Moment of inertia of a solid cylinder (mass \\(M\\), radius \\(R\\), length \\(L\\)) about an axis through the centre, perpendicular to the symmetry axis?","pack":"puc_physics_jee_neet_100","qtype":"numerical","block":"rotation"}$p022c$::jsonb, $p022o$["\\(M(R^2/4 + L^2/12)\\)","\\(\\tfrac12 MR^2\\) only","\\(ML^2/12\\) only","\\(M(R^2 + L^2)\\)"]$p022o$::jsonb, 0, $p022e$Perpendicular-axis / parallel-axis composition for a solid cylinder.$p022e$),
  ('academic', 'physics', 1516, $p023c${"text":"An ice skater pulls arms inward while spinning on ice. What quantity stays conserved (ideal, no external torque)?","pack":"puc_physics_jee_neet_100","qtype":"conceptual","block":"rotation"}$p023c$::jsonb, $p023o$["Angular momentum \\(L\\).","Rotational kinetic energy.","Moment of inertia alone.","Linear momentum only."]$p023o$::jsonb, 0, $p023e$\(L = I\omega\); \(I\) decreases ⇒ \(\omega\) increases.$p023e$),
  ('academic', 'physics', 1522, $p024c${"text":"Solid sphere vs hollow spherical shell, same \\(m,R\\), roll without slipping down the same incline. Ratio of linear accelerations \\(a_{\\mathrm{solid}}/a_{\\mathrm{hollow}}\\)?","pack":"puc_physics_jee_neet_100","qtype":"numerical","block":"rotation"}$p024c$::jsonb, $p024o$["\\(25/21\\)","\\(21/25\\)","\\(5/7\\)","\\(1\\)"]$p024o$::jsonb, 0, $p024e$\(a = g\sin\theta/(1+k^2/R^2)\); \(2/5\) vs \(2/3\) for \(k^2/R^2\).$p024e$),
  ('academic', 'physics', 1528, $p025c${"text":"Physical meaning of radius of gyration \\(k\\)?","pack":"puc_physics_jee_neet_100","qtype":"conceptual","block":"rotation"}$p025c$::jsonb, $p025o$["Distance from axis at which the entire mass could be concentrated to give the same \\(I\\).","The radius of the trajectory in circular motion.","The distance from CM to the geometric centre always.","The lever arm of friction only."]$p025o$::jsonb, 0, $p025e$\(I = Mk^2\) defines \(k\).$p025e$),
  ('academic', 'physics', 1535, $p026c${"text":"Uniform rod length \\(L\\), mass \\(M\\), pivoted at one end, released horizontally. Initial angular acceleration?","pack":"puc_physics_jee_neet_100","qtype":"numerical","block":"rotation"}$p026c$::jsonb, $p026o$["\\(3g/(2L)\\)","\\(g/L\\)","\\(2g/L\\)","\\(g/(2L)\\)"]$p026o$::jsonb, 0, $p026e$\(\tau = MgL/2\), \(I = ML^2/3\), \(\alpha = \tau/I\).$p026e$),
  ('academic', 'physics', 1541, $p027c${"text":"Does the angular velocity vector point along the direction the rim is moving?","pack":"puc_physics_jee_neet_100","qtype":"conceptual","block":"rotation"}$p027c$::jsonb, $p027o$["No — it lies along the rotation axis (right-hand rule), not along tangential motion.","Yes — it is tangent to the circle.","Yes — it points toward the centre.","Only for clockwise rotation."]$p027o$::jsonb, 0, $p027e$\(\vec\omega\) is axial; velocity is tangential.$p027e$),
  ('academic', 'physics', 1547, $p028c${"text":"Uniform solid disc rolls without slipping. Ratio \\(K_{\\mathrm{rot}}/K_{\\mathrm{total}}\\)?","pack":"puc_physics_jee_neet_100","qtype":"numerical","block":"rotation"}$p028c$::jsonb, $p028o$["\\(1/3\\)","\\(1/2\\)","\\(2/5\\)","\\(1/4\\)"]$p028o$::jsonb, 0, $p028e$\(K_{\mathrm{rot}} = \tfrac14 Mv^2\), \(K_{\mathrm{tot}} = \tfrac34 Mv^2\).$p028e$),
  ('academic', 'physics', 1553, $p029c${"text":"Can the centre of mass of a rigid body lie outside the material of the body?","pack":"puc_physics_jee_neet_100","qtype":"conceptual","block":"rotation"}$p029c$::jsonb, $p029o$["Yes — e.g. uniform ring or horseshoe: CM in the hollow region.","Never — CM must always be inside the bulk.","Only for gases, not solids.","Only if the body is charged."]$p029o$::jsonb, 0, $p029e$CM is a mass-weighted average; geometry can enclose empty space.$p029e$),
  ('academic', 'physics', 1559, $p030c${"text":"\\(\\vec\\tau = \\vec r \\times \\vec F\\). Given \\(\\vec r = 2\\hat i + \\hat j\\), \\(\\vec F = \\hat i - \\hat k\\), find \\(\\vec\\tau\\).","pack":"puc_physics_jee_neet_100","qtype":"numerical","block":"rotation"}$p030c$::jsonb, $p030o$["\\(-\\hat i + 2\\hat j - \\hat k\\)","\\(\\hat i + 2\\hat j + \\hat k\\)","\\(2\\hat i - \\hat j + \\hat k\\)","\\(\\vec 0\\)"]$p030o$::jsonb, 0, $p030e$Expand the determinant for the cross product.$p030e$),
  ('academic', 'physics', 1566, $p031c${"text":"According to the shell theorem, what is gravitational field at the exact centre of a uniform spherical Earth model?","pack":"puc_physics_jee_neet_100","qtype":"conceptual","block":"gravitation_shm"}$p031c$::jsonb, $p031o$["Exactly zero by symmetry.","Infinite.","Same as at the surface.","Maximum in magnitude."]$p031o$::jsonb, 0, $p031e$Interior shells contribute cancelling fields at the centre.$p031e$),
  ('academic', 'physics', 1572, $p032c${"text":"Escape speed from Earth is \\(v_e\\). Escape speed from a planet with twice Earth’s mass and twice Earth’s radius?","pack":"puc_physics_jee_neet_100","qtype":"numerical","block":"gravitation_shm"}$p032c$::jsonb, $p032o$["\\(v_e\\) (unchanged)","\\(\\sqrt{2}\\,v_e\\)","\\(v_e/\\sqrt{2}\\)","\\(2v_e\\)"]$p032o$::jsonb, 0, $p032e$\(v \propto \sqrt{M/R}\); doubling both leaves \(\sqrt{M/R}\) the same.$p032e$),
  ('academic', 'physics', 1578, $p033c${"text":"Kepler’s second law (constant areal velocity) follows from conservation of which quantity for a planet in a central gravitational field?","pack":"puc_physics_jee_neet_100","qtype":"conceptual","block":"gravitation_shm"}$p033c$::jsonb, $p033o$["Angular momentum.","Linear momentum.","Mechanical energy alone.","Areal velocity itself as a fundamental quantity."]$p033o$::jsonb, 0, $p033e$Zero torque from central force ⇒ \(L\) constant.$p033e$),
  ('academic', 'physics', 1584, $p034c${"text":"SHM amplitude \\(A\\). Distance from mean position where \\(K = U\\)?","pack":"puc_physics_jee_neet_100","qtype":"numerical","block":"gravitation_shm"}$p034c$::jsonb, $p034o$["\\(A/\\sqrt{2}\\)","\\(A/2\\)","\\(A/\\sqrt{3}\\)","\\(A\\)"]$p034o$::jsonb, 0, $p034e$Equate \(\tfrac12 k(A^2-x^2) = \tfrac12 kx^2\).$p034e$),
  ('academic', 'physics', 1590, $p035c${"text":"In damped harmonic motion, what happens to amplitude as \\(t \\to \\infty\\)?","pack":"puc_physics_jee_neet_100","qtype":"conceptual","block":"gravitation_shm"}$p035c$::jsonb, $p035o$["It decays (typically exponentially) toward zero.","It grows without bound.","It stays exactly constant.","It oscillates between 0 and \\(2A\\)."]$p035o$::jsonb, 0, $p035e$Dissipation removes energy from the oscillator.$p035e$),
  ('academic', 'physics', 1597, $p036c${"text":"Point masses \\(m\\) and \\(4m\\) separated by \\(r\\). Distance from the smaller mass \\(m\\) where net gravitational field is zero?","pack":"puc_physics_jee_neet_100","qtype":"numerical","block":"gravitation_shm"}$p036c$::jsonb, $p036o$["\\(r/3\\)","\\(r/5\\)","\\(r/2\\)","\\(2r/5\\)"]$p036o$::jsonb, 0, $p036e$Set \(Gm/x^2 = G(4m)/(r-x)^2\) ⇒ \(x = r/3\) between them.$p036e$),
  ('academic', 'physics', 1603, $p037c${"text":"Why is apparent weight slightly less at the equator than at the poles (same altitude model)?","pack":"puc_physics_jee_neet_100","qtype":"conceptual","block":"gravitation_shm"}$p037c$::jsonb, $p037o$["Centrifugal (inertial) effect of Earth’s rotation and larger equatorial radius (bulge).","Gravity is weaker because the equator is colder.","Air is thinner at the equator only.","Coriolis force directly reduces scale reading at rest."]$p037o$::jsonb, 0, $p037e$Smaller effective \(g\) at equator: rotation and distance from centre.$p037e$),
  ('academic', 'physics', 1609, $p038c${"text":"In SHM, \\(v_{\\max}\\) and \\(a_{\\max}\\) are given. Amplitude \\(A\\)?","pack":"puc_physics_jee_neet_100","qtype":"numerical","block":"gravitation_shm"}$p038c$::jsonb, $p038o$["\\(v_{\\max}^2/a_{\\max}\\)","\\(a_{\\max}/v_{\\max}\\)","\\(v_{\\max}/a_{\\max}\\)","\\(a_{\\max} v_{\\max}\\)"]$p038o$::jsonb, 0, $p038e$\(v_{\max} = A\omega\), \(a_{\max} = A\omega^2\) ⇒ \(A = v_{\max}^2/a_{\max}\).$p038e$),
  ('academic', 'physics', 1615, $p039c${"text":"Does the period of a simple pendulum (small oscillations) depend on the bob’s mass?","pack":"puc_physics_jee_neet_100","qtype":"conceptual","block":"gravitation_shm"}$p039c$::jsonb, $p039o$["No — \\(T = 2\\pi\\sqrt{L/g}\\) for ideal simple pendulum.","Yes — heavier bobs swing slower.","Yes — period is proportional to mass.","Only if the string has mass."]$p039o$::jsonb, 0, $p039e$Mass cancels in the equation of motion for point bob.$p039e$),
  ('academic', 'physics', 1621, $p040c${"text":"Low circular orbit skimming Earth’s surface (ignore drag). Orbital period in terms of \\(R\\) and \\(g\\)?","pack":"puc_physics_jee_neet_100","qtype":"numerical","block":"gravitation_shm"}$p040c$::jsonb, $p040o$["\\(2\\pi\\sqrt{R/g}\\) (≈ 84.6 min for Earth)","\\(2\\pi\\sqrt{g/R}\\)","\\(\\pi\\sqrt{R/g}\\)","\\(2\\pi R/g\\)"]$p040o$::jsonb, 0, $p040e$\(v = \sqrt{gR}\), circumference \(2\pi R\).$p040e$),
  ('academic', 'physics', 1628, $p041c${"text":"Why do raindrops approach a constant terminal speed instead of accelerating at \\(g\\) indefinitely?","pack":"puc_physics_jee_neet_100","qtype":"conceptual","block":"fluids"}$p041c$::jsonb, $p041o$["Drag (viscous/air resistance) balances weight at terminal velocity.","Gravity switches off after a few seconds.","Raindrops lose mass as they fall.","Buoyancy exactly cancels gravity for all drops."]$p041o$::jsonb, 0, $p041e$Net force goes to zero when drag equals weight.$p041e$),
  ('academic', 'physics', 1634, $p042c${"text":"Two soap bubbles radii \\(R_1, R_2\\) coalesce isothermally in vacuum. Radius of new bubble?","pack":"puc_physics_jee_neet_100","qtype":"numerical","block":"fluids"}$p042c$::jsonb, $p042o$["\\(\\sqrt{R_1^2 + R_2^2}\\)","\\(R_1 + R_2\\)","\\(\\sqrt[3]{R_1^3 + R_2^3}\\) only (pressure ignored)","\\(\\sqrt{R_1 R_2}\\)"]$p042o$::jsonb, 0, $p042e$For isothermal coalescence with \(PV \propto R^2\) for bubbles, \(R^2 = R_1^2 + R_2^2\).$p042e$),
  ('academic', 'physics', 1640, $p043c${"text":"Bernoulli along a horizontal streamline: if speed increases, what happens to pressure?","pack":"puc_physics_jee_neet_100","qtype":"conceptual","block":"fluids"}$p043c$::jsonb, $p043o$["Pressure decreases.","Pressure increases.","Pressure is unchanged.","Pressure oscillates sinusoidally."]$p043o$::jsonb, 0, $p043e$Higher kinetic energy density ⇒ lower pressure for fixed height.$p043e$),
  ('academic', 'physics', 1646, $p044c${"text":"Water in a horizontal pipe: ratio of cross-sectional areas at two points is \\(1:2\\). Ratio of speeds \\(v_1:v_2\\)?","pack":"puc_physics_jee_neet_100","qtype":"numerical","block":"fluids"}$p044c$::jsonb, $p044o$["\\(2:1\\)","\\(1:2\\)","\\(1:1\\)","\\(4:1\\)"]$p044o$::jsonb, 0, $p044e$Continuity: \(A_1 v_1 = A_2 v_2\).$p044e$),
